function ModelHeroExtra:OnModelInit()
	self:ModelNetMsgRecv(LProtoIds.HeroSetNameResp,function (...) self:OnHeroSetNameResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HeroFavorabilityInfoResp,function (...) self:OnHeroFavorabilityInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HeroSetShowResp, function(...) self:OnHeroSetShowResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HeroGiveGiftResp, function(...) self:OnHeroGiveGiftResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HeroInteractionResp, function(...) self:OnHeroInteractionResp(...) end)
	-- self:ModelNetMsgRecv(LProtoIds.HeroInteractQuestResp, function(...) self:OnHeroInteractQuestResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.HeroInteractGameOpsResp, function(...) self:OnHeroInteractGameOpsResp(...) end)

	self:InitHeroFavorabilityRef()
end


