--- req
function ModelHeroExtra:OnHeroSetNameReq(heroId,name)
	local pb = LProtoHelper.CreateProto(LProtoIds.HeroSetNameReq)
	pb.heroId = heroId
	pb.name = name
	SendMessage(pb,LProtoIds.HeroSetNameReq)
end

function ModelHeroExtra:OnHeroSetShowReq(heroEffId)
	local pb = LProtoHelper.CreateProto(LProtoIds.HeroSetShowReq)
	pb.effectId = heroEffId
	SendMessage(pb,LProtoIds.HeroSetShowReq)
end
function ModelHeroExtra:OnHeroGiveGiftReq(id,itemData)
	local pb = LProtoHelper.CreateProto(LProtoIds.HeroGiveGiftReq)
	pb.refId = id
	for k,v in pairs(itemData) do
		local item = pb.items:add()
		item.refId = v._refId
		item.num = v._num
	end
	SendMessage(pb,LProtoIds.HeroGiveGiftReq)
end
function ModelHeroExtra:OnHeroInteractionReq(heroRefId,effId,status)--1/2
	local pb = LProtoHelper.CreateProto(LProtoIds.HeroInteractionReq)
	pb.heroRefId = heroRefId
	interactr = pb.interactionList:add()
	interactr.effId = effId
	local loveInfo = gModelHero:GetFavorabilityInfo(heroRefId)
	interactr.status = status+(loveInfo and (loveInfo.interactionList[effId] or 0) or 0)
	SendMessage(pb,LProtoIds.HeroInteractionReq)
end

--- 英雄觉醒激活额外技能
function ModelHeroExtra:OnHeroTreeActiveExtraSkillReq(heroTreeActInfo)
	local pb = LProtoHelper.CreateProto(LProtoIds.HeroTreeActiveExtraSkillReq)
	pb.heroId = heroTreeActInfo.heroId
	pb.pointRefId = heroTreeActInfo.pointRefId
	pb.extraSkillCostRefId = heroTreeActInfo.extraSkillCostRefId

	local appointedList = heroTreeActInfo.appointedList
	for k,v in pairs(appointedList) do
		for _k,id in pairs(v) do
			table.insert(pb.appointeds,id)
		end
	end

	local rangeList = heroTreeActInfo.rangeList
	for k,v in pairs(rangeList) do
		for _k,id in pairs(v) do
			table.insert(pb.ranges,id)
		end
	end

	local items = pb.items
	local itemsList = heroTreeActInfo.rangItemList
	for i,v in pairs(itemsList) do
		for refId,num in pairs(v) do
			local tNum = tonumber(num)
			if tNum > 0 then
				local itemInfo = items:add()
				itemInfo.refId = tonumber(refId)
				itemInfo.num = tNum
			end
		end
	end
	SendMessage(pb,LProtoIds.HeroTreeActiveExtraSkillReq)
end
