function ModelHeroExtra:OnHeroSetShowResp(pb)
	local effectId = gModelHero._gardenShowHeroEffRefId
	gModelHero._gardenShowHeroEffRefId = pb.effectId
	if effectId>0 and pb.effectId ~= effectId then 
		GF.ShowMessage(ccClientText(41626))
		FireEvent(EventNames.FAVORABILITY_SPINE_UPDATE,pb.effectId)
	end
end

function ModelHeroExtra:OnHeroGiveGiftResp(pb)
	local heroRefId = pb.favorabilityInfo.heroRefId
	local oldLoveInfo = gModelHero:GetFavorabilityInfo(heroRefId)
	local oldLoveLv = oldLoveInfo and oldLoveInfo.loveLevel or 0
	local newLoveLv = pb.favorabilityInfo.loveLevel
	gModelHero:OnSetHeroFavorability(pb.favorabilityInfo)
	local oldTotalLv = gModelHero._loveTotalLevel
	local oldTotalValue = gModelHero._loveTotalValue
	gModelHero._loveTotalLevel = pb.loveLevel
	gModelHero._loveTotalValue = pb.loveValue
	local isPrivilege = false
	local ref = GameTable.CharacterFavorabilityRef[newLoveLv]
	if oldLoveLv~=newLoveLv and ref and (ref.text1~="" or ref.text2~="") then 
		isPrivilege = true
	end
	if pb.addLoveValue and pb.addLoveValue>0 then
		-- GF.ShowMessage(string.replace(ccClientText(41629),pb.addLoveValue))
		FireEvent(EventNames.FAVORABILITY_EXP_UPDATE,pb.addLoveValue)
	end

	if oldTotalLv ~= pb.loveLevel or oldTotalValue ~=  pb.loveValue then
		FireEvent(EventNames.FAVORABILITY_EXP_CHANGED)
	end
	if oldTotalLv~=0 and gModelHero._loveTotalLevel~=oldTotalLv then 
		FireEvent(EventNames.FAVORABILITY_LOVE_UPLV,{isPrivilege=isPrivilege,heroRefId = heroRefId,isTotal = true,addExp=pb.addLoveValue })
	elseif isPrivilege then
		FireEvent(EventNames.FAVORABILITY_LOVE_UPLV,{isPrivilege=isPrivilege,heroRefId = heroRefId,isTotal = false,addExp=pb.addLoveValue })
	end
	
end

