function ModelHeroExtra:GetHeroResetNameCharNum()
	local nameNum = gModelHero:GeConfigByKey("nameNum")
	if not nameNum then
		nameNum = ModelHeroExtra.NAME_MAX_CHARNUM
		if LOG_INFO_ENABLED then
			printInfoNR("HeroConfigRef 可配置 nameNum 字段，表示当前的可设置英雄备注名字符长度，默认长度为：" .. nameNum)
		end
	end
	return nameNum
end

function ModelHeroExtra:GetHeroNameByServerData(serverData)
	if not serverData then return "" end
	return serverData.name
end

function ModelHeroExtra:IsResetHeroNameByServerData(serverData)
	local isInit = self:IsInitHeroNameByServerData(serverData)
	return not isInit
end

function ModelHeroExtra:IsInitHeroNameByServerData(serverData)
	if not serverData then return false end
	local name = self:GetHeroNameByServerData(serverData)
	if string.isempty(name) then return true end
	if self:CheckResetNameIsSameInitName(serverData) then
		return true
	end
	return false
end

function ModelHeroExtra:GetHeroConfigNameByServerData(serverData,needColor)
	if not serverData then  return "" end
	local refId = serverData.refId
	local star = serverData.star
	local form = serverData.form
	if needColor then
		return gModelHero:GetColoredHeroName(refId, star,form)
	else
		return gModelHero:GetHeroNameByRefId(refId, star,form)
	end
end

function ModelHeroExtra:CheckResetNameIsSameInitName(heroData)
	if not heroData then return false end
	local name = self:GetHeroNameByServerData(heroData)
	if string.isempty(name) then return false end
	local configName = self:GetHeroConfigNameByServerData(heroData)
	return configName == name
end

--- heroData：英雄serverData
--- needColor：需要根据星级变化颜色
function ModelHeroExtra:GetHeroSetName(heroData,needColor)
	if not heroData then  return "" end
	local refId = heroData.refId
	local star = heroData.star
	local name = self:GetHeroNameByServerData(heroData)
	local isEmpty = string.isempty(name)
	if isEmpty then
		--- 空的取英雄名字
		name = self:GetHeroConfigNameByServerData(heroData,needColor)
	else
		if needColor then
			local color = gModelHero:GetHeroNameColorByRefId(refId, star)
			if color then
				name = LUtil.FormatColorStr(name, "#" .. color)
			end
		end
	end
	return name
end

function ModelHeroExtra:CheckIsMyHero(id)
	local serverData = gModelHero:GetHeroServerDataById(id)
	return serverData and serverData ~= nil or false
end

