function ModelHeroExtra:DisposeUpSelf(upSelf,heroServerData,upSelfList,upSelfConfigList)
	local heroRefId = heroServerData.refId
	local heroId = heroServerData.id
	local fuse1 = true
	if upSelf then
		if type(upSelf) == "number" then
			if upSelf > 0 then
				local heroStar = gModelHero:GetHeroInitStarByRefId(heroRefId) or ModelHero.AWAKEN_UP_SELF_STAR
				local dataList = gModelHero:AwakenFilterHero(heroRefId,heroStar,nil,heroId,{})
				local selNum = 0
				local selInfo = {}
				for k,v in pairs(dataList) do
					selNum = selNum + 1
					table.insert(selInfo,v)
				end
				table.insert(upSelfList,selInfo)
				fuse1 = selNum >= upSelf
				table.insert(upSelfConfigList,{
					needRefId = heroRefId,
					needStar = heroStar,
					needNum = upSelf,
					canCompound = fuse1,
					itemType = LItemTypeConst.TYPE_HERO,
				})
			end
		else
			if not string.isempty(upSelf) then
				local heroStar,needNum
				local reachNum = 0
				local upSelfInfos = string.split(upSelf,",")
				for i,v in ipairs(upSelfInfos) do
					v = string.split(v,"=")
					needNum = tonumber(v[1])
					heroStar = tonumber(v[2])
					local dataList = gModelHero:AwakenFilterHero(heroRefId,heroStar,nil,heroId,{})
					local selNum = 0
					local selInfo = {}
					for _k,_v in pairs(dataList) do
						selNum = selNum + 1
						table.insert(selInfo,_v)
					end
					table.insert(upSelfList,selInfo)
					if selNum >= needNum then
						reachNum = reachNum + 1
					end
					table.insert(upSelfConfigList,{
						needRefId = heroRefId,
						needStar = heroStar,
						needNum = needNum,
						canCompound = selNum >= needNum,
						itemType = LItemTypeConst.TYPE_HERO,
					})
				end
				fuse1 = reachNum >= #upSelfInfos
			end
		end
	end
	return fuse1
end

function ModelHeroExtra:GetHeroTreeActNeedItemListByConfig(upSelf,upRange,upItem,heroServerData)
	local fuse1,fuse2,fuse3 = true,true,true
	local heroId = heroServerData.id
	local upSelfConfigList = {}
	local upSelfList = {}
	fuse1 = self:DisposeUpSelf(upSelf,heroServerData,upSelfList,upSelfConfigList)


	local upRangeConfigList = {}
	local upRangeList = {}
	if not string.isempty(upRange) then
		local recordRangHeroIdMap = {}
		local recordRangFullMap = {}
		local needRefId,needStar,needNum
		local range = string.split(upRange,',')
		for i,v in ipairs(range) do
			v = string.split(v,"=")
			needRefId,needStar,needNum = tonumber(v[1]),tonumber(v[2]),tonumber(v[3])
			local dataList,yinghunItemList = gModelHero:AwakenFilterHero(needRefId,needStar,needRefId,heroId,{})
			local selNum = 0
			local selInfo = {}
			for key,val in pairs(dataList) do
				if not recordRangHeroIdMap[key] then
					selNum = selNum + 1
					recordRangHeroIdMap[key] = val
					table.insert(selInfo,val)
				end
			end
			table.insert(upRangeList,selInfo)

			local haveNum = selNum + table.keysize(yinghunItemList)
			local isFull = haveNum >= needNum
			recordRangFullMap[i] = isFull and 1 or 0
			table.insert(upRangeConfigList,{
				needRefId = needRefId,
				needStar = needStar,
				needNum = needNum,
				canCompound = isFull,
				itemType = LItemTypeConst.TYPE_HERO,
			})
		end
		local isFull = true
		for k,v in ipairs(recordRangFullMap) do
			if v < 0 then
				isFull = false
				break
			end
		end
		fuse2 = isFull
	end

	local upItemConfigList = {}
	local upItemList = {}
	if not string.isempty(upItem) then
		local haveNum
		local recordItemFullMap = {}
		local itemType,itemId,itemNum
		local upLvItem = string.split(upItem,",")
		for i,v in ipairs(upLvItem) do
			v = string.split(v,"=")
			itemType,itemId,itemNum = tonumber(v[1]),tonumber(v[2]),tonumber(v[3])
			haveNum = gModelItem:GetNumByRefId(itemId)
			local isFull = haveNum >= itemNum
			recordItemFullMap[i] = isFull and 1 or 0
			table.insert(upItemList,{
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
				needRefId = itemId,
				needNum = itemNum,
				haveNum = haveNum,
			})
			table.insert(upItemConfigList,{
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
				needRefId = itemId,
				needNum = itemNum,
				canCompound = isFull,
				itemType = LItemTypeConst.TYPE_ITEM,
			})
		end
		local isFull = true
		for k,v in ipairs(recordItemFullMap) do
			if v < 0 then
				isFull = false
				break
			end
		end
		fuse3 = isFull
	end

	return {
		upSelfInfo = {
			configList = upSelfConfigList,
			selList = upSelfList,
			fuse = fuse1,
		},
		upRangeInfo = {
			configList = upRangeConfigList,
			selList = upRangeList,
			fuse = fuse2,
		},
		upItemInfo = {
			configList = upItemConfigList,
			selList = upItemList,
			fuse = fuse3,
		},
	}
end

function ModelHeroExtra:AwakenFilterHero(hRefId,hStar,hType,selHeroId,selHeroList,needNum,isSelWnd)
	local saveHeroInfoList = gModelHero:GetSaveHeroInfoList()

	local filterList = {}
	local heroStarList = saveHeroInfoList.heroStarList or {}
	local heroStarSelInfo = heroStarList[hStar] or {}
	local isStatusJoin = false
	local isSpiritHeroJoin = false
	local curAllLv,maxLv
	
	local checkFunc = function(heroStruct,tHeroId)
		isStatusJoin = false
		if gModelSpiritHero:CheckIsSpiritHero(heroStruct:GetRefId()) then
			isSpiritHeroJoin = gModelSpiritHero:CheckSpiritHeroIsHaveLink(heroStruct)
			if isSpiritHeroJoin then
				curAllLv,maxLv = gModelHero:GetTreePointsLvlData(tHeroId)
				if curAllLv then
					if curAllLv < 1 then
						isStatusJoin = true
					end
				end
			else
				isStatusJoin = true
			end
		else
			isStatusJoin = true
		end
		return isStatusJoin
	end

	if hType then
		if hType == 0 then
			for tHeroId, tHeroStruct in pairs(heroStarSelInfo) do
				if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
					if checkFunc(tHeroStruct,tHeroId) then
						filterList[tHeroId] = tHeroStruct
					end
				end
			end
		else
			for tHeroId, tHeroStruct in pairs(heroStarSelInfo) do
				if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
					local raceType = gModelHero:GetHeroType(tHeroStruct:GetRefId())
					if raceType == hType and checkFunc(tHeroStruct,tHeroId) then
						filterList[tHeroId] = tHeroStruct
					end
				end
			end
		end
	else
		local heroRefIdList = saveHeroInfoList.heroRefIdList or {}
		local heroRefIdSelInfo = heroRefIdList[hRefId] or {}
		for tHeroId, tHeroStruct in pairs(heroRefIdSelInfo) do
			if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
				isStatusJoin = isSelWnd or tHeroStruct:GetLockStatus() ~= 1
				if isStatusJoin and heroStarSelInfo[tHeroId] and checkFunc(tHeroStruct,tHeroId) then
					filterList[tHeroId] = tHeroStruct
				end
			end
		end
	end
	local serHeroRace
	if selHeroId then
		local refId = gModelHero:GetRefIdById(selHeroId)
		local ref = refId and gModelHero:GetHeroRef(refId)
		if ref then
			serHeroRace = ref.raceType
		end
	end
	local itemList = {}
	if hType then
		-- 英魂筛选(道具)
		local bagYingHunList = gModelItem:GetBagYingHunList()
		for k,v in pairs(bagYingHunList) do
			local itemRefData = gModelItem:GetYingHunRefByRefId(k)
			if itemRefData then
				local isIns = false
				local refRace,refStar = itemRefData.race,itemRefData.star
				if serHeroRace and serHeroRace == refRace and refStar == hStar then
					isIns = true
				elseif refRace == 0 and refStar == hStar then
					isIns = true
				elseif (hType == 0 or refRace == hType) and refStar == hStar then
					-- 填0时为任意种族都可以
					isIns = true
				elseif refStar == hStar then
					local other = ModelItem.RaceTypeList[refRace]
					isIns = other and other[hType] or false
				end
				if isIns then
					local itemStruct = gModelItem:GetItemServerDataByRefId(k)
					if itemStruct then
						local num = itemStruct._num
						for i = 1,num do
							if needNum and needNum < i then break end
							local key = "itemRace_" .. refRace .. "_" .. i
							itemList[key] = itemStruct
						end
					end
				end
			end
		end
	end
	return filterList,itemList
end

function ModelHeroExtra:GetHeroTreeActNeedItemListByStaticConfig(upSelf,upRange,upItem,heroServerData)
	local fuse1,fuse2,fuse3 = true,true,true
	local heroId = heroServerData.id
	local upSelfConfigList = {}
	local upSelfList = {}
	fuse1 = self:DisposeUpSelf(upSelf,heroServerData,upSelfList,upSelfConfigList)

	local upRangeConfigList = {}
	local upRangeList = {}
	if not string.isempty(upRange) then
		local recordRangHeroIdMap = {}
		local recordRangFullMap = {}
		local needRefId,needStar,needNum
		local range = string.split(upRange,',')
		for i,v in ipairs(range) do
			v = string.split(v,"=")
			needRefId,needStar,needNum = tonumber(v[1]),tonumber(v[2]),tonumber(v[3])
			local dataList,yinghunItemList = self:AwakenFilterHero(needRefId,needStar,needRefId,heroId,{})
			local selNum = 0
			local selInfo = {}
			for key,val in pairs(dataList) do
				if not recordRangHeroIdMap[key] then
					selNum = selNum + 1
					recordRangHeroIdMap[key] = val
					table.insert(selInfo,val)
				end
			end
			table.insert(upRangeList,selInfo)

			local haveNum = selNum + table.keysize(yinghunItemList)
			local isFull = haveNum >= needNum
			recordRangFullMap[i] = isFull and 1 or 0
			table.insert(upRangeConfigList,{
				needRefId = needRefId,
				needStar = needStar,
				needNum = needNum,
				canCompound = isFull,
				itemType = LItemTypeConst.TYPE_HERO,
			})
		end
		local isFull = true
		for k,v in ipairs(recordRangFullMap) do
			if v < 0 then
				isFull = false
				break
			end
		end
		fuse2 = isFull
	end

	local upItemConfigList = {}
	local upItemList = {}
	if not string.isempty(upItem) then
		local haveNum
		local recordItemFullMap = {}
		local itemType,itemId,itemNum
		local upLvItem = string.split(upItem,",")
		for i,v in ipairs(upLvItem) do
			v = string.split(v,"=")
			itemType,itemId,itemNum = tonumber(v[1]),tonumber(v[2]),tonumber(v[3])
			haveNum = gModelItem:GetNumByRefId(itemId)
			local isFull = haveNum >= itemNum
			recordItemFullMap[i] = isFull and 1 or 0
			table.insert(upItemList,{
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
				needRefId = itemId,
				needNum = itemNum,
				haveNum = haveNum,
			})
			table.insert(upItemConfigList,{
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
				needRefId = itemId,
				needNum = itemNum,
				canCompound = isFull,
				itemType = LItemTypeConst.TYPE_ITEM,
			})
		end
		local isFull = true
		for k,v in ipairs(recordItemFullMap) do
			if v < 0 then
				isFull = false
				break
			end
		end
		fuse3 = isFull
	end

	return {
		upSelfInfo = {
			configList = upSelfConfigList,
			selList = upSelfList,
			fuse = fuse1,
		},
		upRangeInfo = {
			configList = upRangeConfigList,
			selList = upRangeList,
			fuse = fuse2,
		},
		upItemInfo = {
			configList = upItemConfigList,
			selList = upItemList,
			fuse = fuse3,
		},
	}
end

