function ModelHeroExtra:CheckHeroTreeExtraSkillPayEnough(payInfo)
	if not payInfo then return false end
	local recordHeroIdMap = {}

	local sortSelList,selList,configList,dataList
	local needNum,needStar
	local autoSelId

	local upSelfInfo = payInfo.upSelfInfo
	if upSelfInfo then
		selList = upSelfInfo.selList
		configList = upSelfInfo.configList
		for i,v in ipairs(configList) do
			dataList = selList[i] or {}
			sortSelList = gModelHero:SortFillHeroList(dataList)
			if #sortSelList > 0 then
				needNum = v.needNum
				local recordNum = 0
				local status = false
				for selIdx,selHeroData in ipairs(sortSelList) do
					autoSelId = selHeroData._id
					recordHeroIdMap[autoSelId] = autoSelId
					recordNum = recordNum + 1
					status = recordNum >= needNum
					if status then break end
				end
				if not status then return false end
			else
				return false
			end
		end
	end

	local upRangeInfo = payInfo.upRangeInfo
	if upRangeInfo then
		configList = upRangeInfo.configList
		selList = upRangeInfo.selList
		for i,v in ipairs(configList) do
			needStar = v.needStar
			dataList = selList[i] or {}
			needNum = v.needNum
			sortSelList = gModelHero:SortFillHeroList(dataList)
			if #sortSelList > 0 then
				local recordNum = 0
				local status = false
				for selIdx,selHeroData in ipairs(sortSelList) do
					autoSelId = selHeroData._id
					if not recordHeroIdMap[autoSelId] then
						recordHeroIdMap[autoSelId] = autoSelId
						recordNum = recordNum + 1
						status = recordNum >= needNum
						if status then break end
					end
				end
			else
				return false
			end
		end
	end

	local upItemInfo = payInfo.upItemInfo
	if upItemInfo then
		configList = upItemInfo.configList
		selList = upItemInfo.selList
		local itemId,itemNum,haveNum
		for i,v in ipairs(configList) do
			itemId = v.itemId
			itemNum = v.itemNum
			haveNum = gModelItem:GetNumByRefId(itemId)
			if haveNum < itemNum then return false end
		end
	end

	return true
end

function ModelHeroExtra:CheckCanUpExtraSkillByHeroServerData(heroServerData,lvRefId)

	--local isFuncOpen = gModelFunctionOpen:CheckIsOpened(10306003)
	local isFuncOpen = false
	if not isFuncOpen then
		return false
	end

	if not heroServerData then return false end

	local treeInfo = heroServerData.treeInfo
	if not treeInfo then return false end

	local extraSkillCostRefIdMap = treeInfo.extraSkillCostRefIdMap
	if not extraSkillCostRefIdMap then return false end

	if not lvRefId then return false end

	local curPointLvRef = gModelHero:GetHeroTreePointLvRef(lvRefId)
	if not curPointLvRef then return false end

	local skillInfo = self:GetHeroTreeSkillList(curPointLvRef)
	if not skillInfo then return false end

	return false
end

--- 检查是否有额外技能可激活
function ModelHeroExtra:CheckHeroTreeIsHaveExtraSkillActByHeroServerData(heroServerData)
	if not heroServerData then return false end

	local heroId = heroServerData.id
	local treeInfoPoints = gModelHero:GetHeroServerTreePoints(heroId)
	if not treeInfoPoints then return false end

	local lvRefId,pointRefId
	local pointLvList
	for k,v in pairs(treeInfoPoints) do
		pointRefId = v.pointRefId
		pointLvList = gModelHero:GetHeroTreePointLvList(pointRefId)
		if pointLvList.pointType == ModelHero.TREE_POINT_TYPE_SKILL then
			lvRefId = v.lvRefId
			if self:CheckCanUpExtraSkillByHeroServerData(heroServerData,lvRefId) then
				return true
			end
		end
	end

	return false
end
