--region 可出售的伙伴，需满足以下条件
--开发需求 #12142
--【后台活动】分表条目类型3支持配置伙伴作为现价（客户端&服务端）
function ModelHeroExtra:CheckBeCapableOfSellHero(heroData)
	local heroRefId = heroData:GetRefId()
	local heroRef = gModelHero:GetHeroRef(heroRefId)
	local heroServerData = heroData:GetServerData()
	--
	local isTry = heroData:IsTryHero()
	--初始星级
	local initStar =heroRef.initStar
	local isInitStar = heroData:GetStar() == initStar
	--出战/锁定/魔晶共鸣
	local heroStatus = heroData:GetStatus()
	local notUsed = heroStatus == 0
	--星灵连结
	local isSpiritLink = gModelSpiritHero:CheckHeroIsHaveLink(heroServerData)
	--星灵觉醒等级/核心等级
	local isSpirtHero =gModelSpiritHero:CheckIsSpiritHero(heroRefId)
	local isInitLvlSpirit = true
	if(isSpirtHero)then
		local treeInfo = heroData:GetTreeInfo()
		local curLvl,maxLvl = gModelHero:GetTreePointsCurLvAndMaxLv(treeInfo)--觉醒等级
		isInitLvlSpirit = curLvl == 0
	end
	return not isTry and isInitStar and notUsed and not isSpiritLink and isInitLvlSpirit
end
--endregion
--region 获取x个可出售伙伴Id
function ModelHeroExtra:GetBeCapableOfSellHeroIdList(refId,num)
	local idList = {}
	local playerHeroList = gModelHero:GetHeroList()
	for i, v in pairs(playerHeroList) do
		local heroData = v
		if(heroData:GetRefId() == refId)then
			local beCapableOfSell = self:CheckBeCapableOfSellHero(heroData)
			if(beCapableOfSell)then
				table.insert(idList,v:GetId())
			end
		end
	end
	local list = {}
	for i, v in pairs(idList) do
		if(num and #list <num)then
			table.insert(list,v)
		end
	end
	table.sort(list, function(a,b)
			return  a>b
	end)
	return num and list or idList
end
--endregion

