--- 是否静止 http://192.168.16.2:3002/issues/1168
function ModelHeroExtra:CheckBookIsCalm(skinRefId)
	local effectRef = GameTable.CharacterEffectRef[skinRefId]
	if not effectRef then return true end
	local refId = effectRef.heroType
	if refId and refId > 0 then
		if not gModelHeroBook:FindHeroInfoStatusByHeroRefId(refId) then
			--- 未获得英雄
			return true
		end
	end
	if not gModelHero:GetOriginId(skinRefId) then
		--- 非变形
		local isHeroSkin = gModelHero:CheckHeroRefIdHasSkinId(skinRefId)
		local notActSkin = gModelHero:GetHeroSkinInfoByRefId(skinRefId) == nil
		if isHeroSkin and notActSkin then
			--- 皮肤未激活
			return true
		end
		return false
	end
	--- 如果本身没有皮肤，静止状态
	local skinInfo = gModelHero:GetHeroSkinInfoByRefId(skinRefId)
	return skinInfo == nil or false
end

