	local recordBattleSounds = {}
	local SpActionSound
	for k,v in pairs(GameTable.CharacterFavorabilityRef) do
		SpActionSound = v.SpActionSound
		if ModelHeroExtra.RECORD_SKILLSOUND_MAP[SpActionSound] then
			table.insert(recordBattleSounds,{
				SpActionSound = SpActionSound,
				refId = v.refId
			})
		end
	end
	table.sort(recordBattleSounds,function(a, b) return a.refId > b.refId end)
	self._recordBattleSounds = recordBattleSounds
end

function ModelHeroExtra:GetHeroFavorabilitySounds(loveLevel,effData)
	if not effData then return end

	local skinSkillType = effData.skinSkillType
	if not skinSkillType then return end

	local SpActionSound
	for i,v in ipairs(self._recordBattleSounds) do
		if loveLevel >= v.refId then
			SpActionSound = v.SpActionSound
			if ModelHeroExtra.RECORD_SKILLSOUND_MAP[SpActionSound] == skinSkillType then
				return SpActionSound
			end
		end
	end
end

