--- 升星珍稀 类型 7：为道具(光暗)
local UPSTAR_RARETYPE = {
	[4] = true,[5] = true,[7] = true,
}

--- 升星里面是否选择了种族 4,5 的英雄或者仙灵道具
function ModelHeroExtra:CheckUpStarIsSelRare(rSelHeroMap,rSelItemMap,rangNeedInfo)
	local isSelRare = false
	---@type StructHero
	local sHero
	local raceType
	local yinhunTypeData
	local heroList = gModelHero:GetHeroList()
	for i,v in ipairs(rangNeedInfo) do
		if isSelRare then break end
		if v.needRefId == 0 then
			--- 全种族，需要检测
			local rSelHeros = rSelHeroMap[i]
			if rSelHeros then
				for heroId,status in pairs(rSelHeros) do
					sHero = heroList[heroId]
					if sHero then
						raceType = gModelHero:GetHeroRace(sHero:GetRefId())
						if UPSTAR_RARETYPE[raceType] then
							isSelRare = true
							break
						end
					end
				end
			end
			local rSelItems = rSelItemMap[i]
			if rSelItems then
				for itemId,itemNum in pairs(rSelItems) do
					yinhunTypeData = gModelItem:GetYingHunRefByRefId(itemId)
					if yinhunTypeData and UPSTAR_RARETYPE[yinhunTypeData.race] then
						isSelRare = true
						break
					end
				end
			end
		end
	end
	return isSelRare
end


function ModelHeroExtra:GetMaxGradeByClassType(classType,grade,star)
	local maxGrade
	local isStarLimit = false
	local sortClassList = gModelHero:GetSortHeroClassRefListByClassType(classType)
	local needStar,rGrade
	for i,v in ipairs(sortClassList) do
		rGrade = v.grade
		if rGrade >= grade then
			needStar = v.needStar
			if needStar > 0 then
				if star >= needStar then
					maxGrade = rGrade
				else
					--- 星级限制，但是等级可以升上去
					isStarLimit = true
					maxGrade = rGrade
					break
				end
			else
				maxGrade = rGrade
			end
		end
	end
	if not maxGrade then
		maxGrade = self:OnlyCalcMaxGradeByClassType(classType)
	end
	return maxGrade,isStarLimit
end

function ModelHeroExtra:OnlyCalcMaxGradeByClassType(classType)
	if not self._initClassTypeMaxGradeMap then
		self._initClassTypeMaxGradeMap = {}
	end
	local maxGrade = self._initClassTypeMaxGradeMap[classType]
	if not maxGrade then
		for k,v in pairs(GameTable.CharacterClassRef) do
			if v.type == classType then
				if not maxGrade then
					maxGrade = v.grade
				elseif maxGrade < v.grade then
					maxGrade = v.grade
				end
			end
		end
		self._initClassTypeMaxGradeMap[classType] = maxGrade
	end
	return maxGrade
end


