function ModelHeroExtra:GetHeroDrawingAllAgesByPrefabName(spineName)
	local ref = gLGameLanguage:GetShieldLHjdRef(spineName)
	if not ref then return end

	local parseShieldHeroDrawingAllAges = self._parseShieldHeroDrawingAllAges
	if not parseShieldHeroDrawingAllAges then
		parseShieldHeroDrawingAllAges = {}
		self._parseShieldHeroDrawingAllAges = parseShieldHeroDrawingAllAges
	end
	local parseShieldHeroDrawingAllAge = parseShieldHeroDrawingAllAges[spineName]
	if parseShieldHeroDrawingAllAge then return parseShieldHeroDrawingAllAge end


	local heroDrawingAllAges = ref.heroDrawingAllAges
	local resType = LPlayerPrefs.GetLocalization()
	if resType then
		if resType == 3 then
			heroDrawingAllAges = ref.heroDrawingAllAges1
		elseif resType == 4 then
			heroDrawingAllAges = ref.heroDrawingAllAges2
		end
	end
	parseShieldHeroDrawingAllAge = self:SetHeroDrawingAllAgesByPrefabName(spineName,heroDrawingAllAges)
	return parseShieldHeroDrawingAllAge
end

