			})
		end
	end
	parseLHDrawingAllAges[effId] = parseLHKPDrawingAllAge
	return parseLHKPDrawingAllAge
end

function ModelHeroExtra:GetLHDrawingAllAgesDataByPrefabName(spineName)
	local parseShieldLHDrawingAllAges = self._parseShieldLHDrawingAllAges
	if not parseShieldLHDrawingAllAges then
		parseShieldLHDrawingAllAges = {}
		self._parseShieldLHDrawingAllAges = parseShieldLHDrawingAllAges
	end
	local parseShieldLHDrawingAllAge = parseShieldLHDrawingAllAges[spineName]
	if parseShieldLHDrawingAllAge then return parseShieldLHDrawingAllAge end

	local ref = gLGameLanguage:GetShieldLHjdRef(spineName)
	if not ref then return nil end

	local LHDrawingAllAges = ref.LHDrawingAllAges
	local resType = LPlayerPrefs.GetLocalization()
	if resType then
		if resType == 3 then
			LHDrawingAllAges = ref.LHDrawingAllAges1
		elseif resType == 4 then
			LHDrawingAllAges = ref.LHDrawingAllAges2
		end
	end
	parseShieldLHDrawingAllAge = self:SetLHDrawingAllAgesDataByPrefabName(spineName,LHDrawingAllAges)
	return parseShieldLHDrawingAllAge
end

function ModelHeroExtra:SetLHDrawingAllAgesDataByPrefabName(spineName,LHDrawingAllAges)
	local parseShieldLHDrawingAllAges = self._parseShieldLHDrawingAllAges
	if not parseShieldLHDrawingAllAges then
		parseShieldLHDrawingAllAges = {}
		self._parseShieldLHDrawingAllAges = parseShieldLHDrawingAllAges
	end
	local parseShieldLHDrawingAllAge = {}
	if LHDrawingAllAges and #LHDrawingAllAges > 0 then
		for i,v in ipairs(LHDrawingAllAges) do
			v = string.split(v,"=")
			table.insert(parseShieldLHDrawingAllAge,{
				res = v[1],
				pos = LxDataHelper.ParseVector2NotEmpty(v[2]),
				scale = checknumber(v[3]),
				rotate = checknumber(v[4]),
			})
		end
	end
	parseShieldLHDrawingAllAges[spineName] = parseShieldLHDrawingAllAge
	return parseShieldLHDrawingAllAge
end

function ModelHeroExtra:GetPolymorphismNew(refId)
	local tempList = gModelHero:GetPolymorphism(refId)
	if tempList and #tempList > 0 then
		local list = {}
		table.insert(list,{ refId = refId, needStar = 0 })
		for i,v in ipairs(tempList) do
			if self:NeedCheckResType() then
				if not self:CheckBookIsCalm(v.refId) then
					table.insert(list,v)
				end
			else
				table.insert(list,v)
			end
		end
		return list
	end
end

function ModelHeroExtra:NeedCheckResType()
	local resType = LPlayerPrefs.GetLocalization()
	return resType == 3
end

---@param iconBig string 原来的icon
---@param heroEffectRef V_HeroEffectRef
function ModelHeroExtra:GetShieldIconBig(iconBig,heroEffectRef)
	if not heroEffectRef then return iconBig end
	local heroDrawing = gLGameLanguage:GetPrefabName(heroEffectRef.heroDrawing)
	local shieldLHRef = gLGameLanguage:GetShieldLHjdRef(heroDrawing)
	if shieldLHRef then
		local replaceIconBig
		local resType = LPlayerPrefs.GetLocalization()
		if resType then
			if resType == 3 then
				if not string.isempty(shieldLHRef.iconBigHX1) then
					replaceIconBig = shieldLHRef.iconBigHX1
				end
			elseif resType == 4 then
				if not string.isempty(shieldLHRef.iconBigHX2) then
					replaceIconBig = shieldLHRef.iconBigHX2
				end
			end
		end
		if not replaceIconBig and not string.isempty(shieldLHRef.iconBigHX) then
			replaceIconBig = shieldLHRef.iconBigHX
		end
		if replaceIconBig then
			iconBig = replaceIconBig
		end
	end
	return iconBig
end

